const MAX_LEN = parseInt($env.TELEGRAM_MAX_MESSAGE_LENGTH || '4000', 10);
const source = $json.source;
const rawText = $json.responseText || '';

let text = rawText;

if (source === 'telegram' && text.length > MAX_LEN) {
  text = text.substring(0, MAX_LEN - 20) + '... [truncated]';
}

text = text.replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');
text = text.replace(/\*(.*?)\*/g, '<i>$1</i>');
text = text.replace(/`(.*?)`/g, '<code>$1</code>');
text = text.replace(/&(?!amp;|lt;|gt;|#)/g, '&');

return [{ json: { ...$json, messageText: text } }];

const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const cl = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[cl] ?? 1)) {
    console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](JSON.stringify({ timestamp: new Date().toISOString(), level, traceId: $json.sessionId || 'unknown', workflow: 'response-sender', message, meta }));
  }
};
const sc = $json.statusCode || 0;
const ctx = $json._ctx || {};
if (sc === 429) {
  jarvisLog('warn', 'Telegram rate limit hit', { chatId: $json.metadata?.chatId });
} else if (sc === 403) {
  jarvisLog('warn', 'Bot blocked by user', { userId: ctx.userId, chatId: $json.metadata?.chatId });
} else if (sc >= 400) {
  jarvisLog('error', 'Telegram send failed', { statusCode: sc, chatId: $json.metadata?.chatId });
}
return [];
